def append_csv_row(csv_path: Path, fieldnames, row_dict: dict):
    write_header = not csv_path.exists()
    with open(csv_path, "a", newline="") as csv_file:
        writer = csv.DictWriter(csv_file, fieldnames=fieldnames)
